700	\begin{proof}
701	  \uses{def:Scheme_kToSection, def:Scheme_algebraSection}
702	  \leanok
703	  Apply \lstinline{AlgebraicGeometry.finite_appTop_of_universallyClosed} to obtain $\mathtt{RingHom.Finite}\,(C.\mathtt{hom}.\mathtt{appTop}.\mathtt{hom})$, which says $\Gamma(C, \struct C)$ is module-finite over the intermediate ring $\Gamma(\Spec k, \top)$ under the algebra structure $\mathtt{RingHom.toAlgebra}\,(C.\mathtt{hom}.\mathtt{appTop}.\mathtt{hom})$ (registered via \lstinline{letI}). Transfer the base ring from this intermediate to $k$ along the ring iso \lstinline{(Scheme.ΓSpecIso (CommRingCat.of k)).commRingCatIsoToRingEquiv} via \lstinline{Module.Finite.of_equiv_equiv}. The compatibility-of-algebra-maps obligation reduces to showing $\mathtt{kToSection}\,C\,(\op\top).\mathtt{hom} = (C.\mathtt{hom}.\mathtt{appTop}.\mathtt{hom}).\mathtt{comp}\,((\Gamma\!\Spec\!\mathrm{Iso}\,k)^{-1}.\mathtt{hom})$, which collapses by \lstinline{Subsingleton.elim} on the $\top \to \top$ hom-set in $\opens C.\mathtt{left}$ (since the trailing $\rho$ factor $(\mathtt{homOfLE}\,\le_{\top}).\mathtt{op}$ becomes $\mathtt{id}\,(\op\top)$, and $\mathtt{presheaf.map}\,\mathtt{id} = \mathtt{id}$).
704	\end{proof}
