706	\begin{remark}[Iter-045+ assembly into the producer instance]
707	  Iter-044 lands only the \emph{algebraic input} (Theorem~\ref{thm:Scheme_module_finite_globalSections_of_isProper}). Iter-045+ assembles it into the producer instance \lstinline{IsHModuleHomFinite k C (toModuleKSheaf C)} by:
708	  \begin{enumerate}
709	    \item Establishing the constant-sheaf / global-sections \lstinline{LinearEquiv} between $((\mathtt{constantSheaf}).\mathtt{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to \toModuleKSheaf\,C)$ and the global Hom group $(\ModuleCat.\mathrm{of}\,k\,k \to (\mathtt{Sheaf.\Gamma}).\mathtt{obj}\,(\toModuleKSheaf\,C))$ — the $k$-linear lift of \lstinline{constantSheafΓAdj.homEquiv}.
710	    \item Identifying $(\mathtt{Sheaf.\Gamma}).\mathtt{obj}\,(\toModuleKSheaf\,C)$ with $\ModuleCat.\mathrm{of}\,k\,(C.\mathtt{left}.\mathtt{presheaf}.\mathtt{obj}\,(\op\top))$ as $k$-modules.
711	    \item Identifying the Hom group $(\ModuleCat.\mathrm{of}\,k\,k \to \ModuleCat.\mathrm{of}\,k\,M)$ with $M$ as a $k$-module (Hom-from-$k$).
712	    \item Combining via \lstinline{Module.Finite.equiv} with Theorem~\ref{thm:Scheme_module_finite_globalSections_of_isProper}.
713	  \end{enumerate}
714	  Steps 1–3 are algebraic and may take 1–2 iterations; step 4 is a one-liner once the \lstinline{LinearEquiv} chain is in place.
715	\end{remark}
